import { Component } from '@angular/core';
import { FormBuilder, FormGroup, FormArray, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { ElectionService } from '../../services/election.service';
import { Election } from '../../models/models';

@Component({
  selector: 'app-create-election',
  templateUrl: './create-election.component.html',
  styleUrls: ['./create-election.component.css']
})
export class CreateElectionComponent {

  electionForm: FormGroup;
  loading = false;
  error: string | null = null;

  constructor(
    private fb: FormBuilder,
    private electionService: ElectionService,
    private router: Router
  ) {

    this.electionForm = this.fb.group({
      title: ['', Validators.required],
      description: [''],
      countdown: [3600, Validators.required],
      isActive: [false],
      positions: this.fb.array([])
    });

  }

  // ------------------------
  // POSITIONS
  // ------------------------

  get positions(): FormArray {
    return this.electionForm.get('positions') as FormArray;
  }

  addPosition() {
    const position = this.fb.group({
      name: ['', Validators.required],
      description: [''],
      candidates: this.fb.array([])
    });

    this.positions.push(position);
  }

  removePosition(index: number) {
    this.positions.removeAt(index);
  }

  // ------------------------
  // CANDIDATES
  // ------------------------

  candidates(positionIndex: number): FormArray {
    return this.positions.at(positionIndex).get('candidates') as FormArray;
  }

  addCandidate(positionIndex: number) {
    const candidate = this.fb.group({
      name: ['', Validators.required]
    });

    this.candidates(positionIndex).push(candidate);
  }

  removeCandidate(positionIndex: number, candidateIndex: number) {
    this.candidates(positionIndex).removeAt(candidateIndex);
  }

  // ------------------------
  // SUBMIT
  // ------------------------

  submit() {

    if (this.electionForm.invalid) {
      this.error = "Please complete required fields.";
      return;
    }

    this.loading = true;
    this.error = null;

    const electionData: Partial<Election> = this.electionForm.value;

    this.electionService.createElection(electionData)
      .subscribe({
        next: (response) => {

          if (response.success) {
            this.router.navigate(['/admin/elections']);
          } else {
            this.error = response.message || "Failed to create election.";
          }

          this.loading = false;
        },

        error: () => {
          this.error = "Server error while creating election.";
          this.loading = false;
        }
      });

  }

}
